using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// ML.NET input schema — maps directly to the training CSV columns.
/// </summary>
public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

/// <summary>
/// API request / response DTOs for ticket classification.
/// </summary>
public sealed class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public sealed class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

public sealed class ModelEvaluationResult
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public sealed class PerClassMetric
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains an ML.NET multiclass classifier on the ticket CSV,
/// exposes evaluation metrics, and provides thread-safe predictions.
/// </summary>
public sealed class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelEvaluationResult _evaluationResult;
    private readonly string[] _classLabels;

    public TicketModelService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        IDataView data = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

        // Combine Subject + Description into a single text feature, featurise it,
        // then concatenate with Priority for the final feature vector.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        ITransformer model = pipeline.Fit(split.TrainSet);

        // Evaluate on the held-out test split.
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _classLabels = GetClassLabels(split.TrainSet);

        _evaluationResult = new ModelEvaluationResult
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = BuildPerClassMetrics(metrics, _classLabels)
        };

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(model);
    }

    public ModelEvaluationResult Evaluation => _evaluationResult;

    public TicketClassificationResult Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        TicketPrediction prediction = _predictionEngine.Predict(input);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            probabilities[_classLabels[i]] = prediction.Score[i];
        }

        return new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        };
    }

    // ── helpers ──────────────────────────────────────────────────────

    private string[] GetClassLabels(IDataView trainData)
    {
        // Extract distinct Category values from the training set in label-key order.
        var labelColumn = trainData.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        if (keyType is null)
            return [];

        VBuffer<ReadOnlyMemory<char>> labels = default;
        trainData.Schema["Label"].GetKeyValues(ref labels);
        return labels.DenseValues().Select(v => v.ToString()).ToArray();
    }

    private static PerClassMetric[] BuildPerClassMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics, string[] classLabels)
    {
        var result = new List<PerClassMetric>();
        for (int i = 0; i < classLabels.Length; i++)
        {
            result.Add(new PerClassMetric
            {
                ClassName = classLabels[i],
                Precision = i < metrics.PerClassPrecision.Count ? metrics.PerClassPrecision[i] : 0,
                Recall = i < metrics.PerClassRecall.Count ? metrics.PerClassRecall[i] : 0,
                F1Score = i < metrics.PerClassPrecision.Count && i < metrics.PerClassRecall.Count
                    ? 2 * metrics.PerClassPrecision[i] * metrics.PerClassRecall[i]
                      / (metrics.PerClassPrecision[i] + metrics.PerClassRecall[i] + 1e-15)
                    : 0
            });
        }
        return result.ToArray();
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketModelService _modelService;

    public TicketController(TicketModelService modelService) => _modelService = modelService;

    /// <summary>POST /api/ticket/classify — predict the category for a ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        return Ok(_modelService.Predict(request));
    }

    /// <summary>GET /api/ticket/metrics — return training evaluation metrics.</summary>
    [HttpGet("metrics")]
    public ActionResult<ModelEvaluationResult> GetMetrics() => Ok(_modelService.Evaluation);
}

