private string[] GetClassLabels(IDataView trainData)
{
    // Extract distinct Category values from the training set in label-key order.
    var labelColumn = trainData.Schema["Label"];
    var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
    if (keyType is null)
        return [];

    VBuffer<ReadOnlyMemory<char>> labels = default;
    trainData.Schema["Label"].GetKeyValues(ref labels);
    return labels.DenseValues().Select(v => v.ToString()).ToArray();
}

private static PerClassMetric[] BuildPerClassMetrics(
    Microsoft.ML.Data.MulticlassClassificationMetrics metrics, string[] classLabels)
{
    var result = new List<PerClassMetric>();
    for (int i = 0; i < classLabels.Length; i++)
    {
        result.Add(new PerClassMetric
        {
            ClassName = classLabels[i],
            Precision = i < metrics.PerClassPrecision.Count ? metrics.PerClassPrecision[i] : 0,
            Recall = i < metrics.PerClassRecall.Count ? metrics.PerClassRecall[i] : 0,
            F1Score = i < metrics.PerClassPrecision.Count && i < metrics.PerClassRecall.Count
                ? 2 * metrics.PerClassPrecision[i] * metrics.PerClassRecall[i]
                  / (metrics.PerClassPrecision[i] + metrics.PerClassRecall[i] + 1e-15)
                : 0
        });
    }
    return result.ToArray();
}

