1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. /// <summary>
8. /// Trains an ML.NET multiclass classifier on the ticket CSV,
9. /// exposes evaluation metrics, and provides thread-safe predictions.
10. /// </summary>
11. public sealed class TicketModelService
12. {
13.     private readonly MLContext _mlContext;
14.     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
15.     private readonly ModelEvaluationResult _evaluationResult;
16.     private readonly string[] _classLabels;
17. 
18.     public TicketModelService(string dataPath)
19.     {
20.         _mlContext = new MLContext(seed: 42);
21. 
22.         IDataView data = _mlContext.Data.LoadFromTextFile<TicketData>(
23.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
24. 
25.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);
26. 
27.         // Combine Subject + Description into a single text feature, featurise it,
28.         // then concatenate with Priority for the final feature vector.
29.         var pipeline = _mlContext.Transforms.Conversion
30.                 .MapValueToKey("Label", nameof(TicketData.Category))
31.             .Append(_mlContext.Transforms.Text.FeaturizeText(
32.                 "SubjectFeaturized", nameof(TicketData.Subject)))
33.             .Append(_mlContext.Transforms.Text.FeaturizeText(
34.                 "DescriptionFeaturized", nameof(TicketData.Description)))
35.             .Append(_mlContext.Transforms.Concatenate("Features",
36.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
37.             .Append(_mlContext.MulticlassClassification.Trainers
38.                 .SdcaMaximumEntropy("Label", "Features"))
39.             .Append(_mlContext.Transforms.Conversion
40.                 .MapKeyToValue("PredictedLabel"));
41. 
42.         ITransformer model = pipeline.Fit(split.TrainSet);
43. 
44.         // Evaluate on the held-out test split.
45.         IDataView predictions = model.Transform(split.TestSet);
46.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");
47. 
48.         _classLabels = GetClassLabels(split.TrainSet);
49. 
50.         _evaluationResult = new ModelEvaluationResult
51.         {
52.             MacroAccuracy = metrics.MacroAccuracy,
53.             MicroAccuracy = metrics.MicroAccuracy,
54.             LogLoss = metrics.LogLoss,
55.             LogLossReduction = metrics.LogLossReduction,
56.             PerClassMetrics = BuildPerClassMetrics(metrics, _classLabels)
57.         };
58. 
59.         _predictionEngine = _mlContext.Model
60.             .CreatePredictionEngine<TicketData, TicketPrediction>(model);
61.     }
62. 
63.     public ModelEvaluationResult Evaluation => _evaluationResult;
64. 
65.     public TicketClassificationResult Predict(TicketRequest request)
66.     {
67.         var input = new TicketData
68.         {
69.             Subject = request.Subject,
70.             Description = request.Description,
71.             Priority = request.Priority
72.         };
73. 
74.         TicketPrediction prediction = _predictionEngine.Predict(input);
75. 
76.         var probabilities = new Dictionary<string, float>();
77.         for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
78.         {
79.             probabilities[_classLabels[i]] = prediction.Score[i];
80.         }
81. 
82.         return new TicketClassificationResult
83.         {
84.             PredictedCategory = prediction.Category,
85.             Probabilities = probabilities
86.         };
87.     }
88. 
89.     // ── helpers ──────────────────────────────────────────────────────
90. 
91.     private static string[] GetClassLabels(IDataView trainData)
92.     {
93.         var labelColumn = trainData.Schema["Label"];
94.         VBuffer<ReadOnlyMemory<char>> labels = default;
95.         Microsoft.ML.Data.SchemaAnnotationsExtensions
96.             .GetKeyValues(labelColumn, ref labels);
97.         return labels.DenseValues().Select(v => v.ToString()).ToArray();
98.     }
99. 
100.     private static PerClassMetric[] BuildPerClassMetrics(
101.         Microsoft.ML.Data.MulticlassClassificationMetrics metrics, string[] classLabels)
102.     {
103.         var cm = metrics.ConfusionMatrix;
104.         var result = new List<PerClassMetric>();
105.         for (int i = 0; i < classLabels.Length; i++)
106.         {
107.             double precision = i < cm.PerClassPrecision.Count ? cm.PerClassPrecision[i] : 0;
108.             double recall = i < cm.PerClassRecall.Count ? cm.PerClassRecall[i] : 0;
109.             double f1 = (precision + recall) > 0
110.                 ? 2 * precision * recall / (precision + recall)
111.                 : 0;
112. 
113.             result.Add(new PerClassMetric
114.             {
115.                 ClassName = classLabels[i],
116.                 Precision = precision,
117.                 Recall = recall,
118.                 F1Score = f1
119.             });
120.         }
121.         return result.ToArray();
122.     }
123. }
